1	import { APICallError } from '@ai-sdk/provider';
2	import { isAbortError } from './is-abort-error';
3	
4	const FETCH_FAILED_ERROR_MESSAGES = ['fetch failed', 'failed to fetch'];
5	
6	const BUN_ERROR_CODES = [
7	  'ConnectionRefused',
8	  'ConnectionClosed',
9	  'FailedToOpenSocket',
10	  'ECONNRESET',
11	  'ECONNREFUSED',
12	  'ETIMEDOUT',
13	  'EPIPE',
14	];
15	
16	function isBunNetworkError(error: unknown): error is Error & { code?: string } {
17	  if (!(error instanceof Error)) {
18	    return false;
19	  }
20	
21	  const code = (error as any).code;
22	  if (typeof code === 'string' && BUN_ERROR_CODES.includes(code)) {
23	    return true;
24	  }
25	
26	  return false;
27	}
28	
29	export function handleFetchError({
30	  error,
31	  url,
32	  requestBodyValues,
33	}: {
34	  error: unknown;
35	  url: string;
36	  requestBodyValues: unknown;
37	}) {
38	  if (isAbortError(error)) {
39	    return error;
40	  }
41	
42	  // unwrap original error when fetch failed (for easier debugging):
43	  if (
44	    error instanceof TypeError &&
45	    FETCH_FAILED_ERROR_MESSAGES.includes(error.message.toLowerCase())
46	  ) {
47	    const cause = (error as any).cause;
48	
49	    if (cause != null) {
50	      // Failed to connect to server:
51	      return new APICallError({
52	        message: `Cannot connect to API: ${cause.message}`,
53	        cause,
54	        url,
55	        requestBodyValues,
56	        isRetryable: true, // retry when network error
57	      });
58	    }
59	  }
60	
61	  if (isBunNetworkError(error)) {
62	    return new APICallError({
63	      message: `Cannot connect to API: ${error.message}`,
64	      cause: error,
65	      url,
66	      requestBodyValues,
67	      isRetryable: true,
68	    });
69	  }
70	
71	  return error;
72	}
