          environmentVariableName: 'OPENAI_API_KEY',
          description: 'OpenAI',
        })}`,
        'OpenAI-Organization': options.organization,
        'OpenAI-Project': options.project,
        ...options.headers,
      },
      `ai-sdk/openai/${VERSION}`,
    );

  const createImageModel = (modelId: OpenAIImageModelId) =>
    new OpenAIImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: OpenAIResponsesModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as OpenAIProvider;
}

export const openai = createOpenAI();
```

**Google Example** (`/packages/google/src/google-provider.ts`):

```typescript
const createImageModel = (
  modelId: GoogleGenerativeAIImageModelId,
  settings: GoogleGenerativeAIImageSettings = {},
) =>
  new GoogleGenerativeAIImageModel(modelId, settings, {
    provider: providerName,
    baseURL,
    headers: getHeaders,
    fetch: options.fetch,
  });

provider.image = createImageModel;
```

**Fal Example** (`/packages/fal/src/fal-provider.ts`):

```typescript
const createImageModel = (modelId: FalImageModelId) =>
  new FalImageModel(modelId, {
    provider: 'fal.image',
    baseURL: baseURL ?? defaultBaseURL,
    headers: getHeaders,
    fetch: options.fetch,
  });
```

### 7. **API Key and Base URL Handling Pattern**

All providers follow a consistent pattern:

**API Key Loading:**
- First check: constructor options
- Second check: environment variables (provider-specific names: `OPENAI_API_KEY`, `GOOGLE_GENERATIVE_AI_API_KEY`, `FAL_API_KEY`, etc.)
- Fallback: Throw error with helpful message

**Base URL Handling:**
- Constructor option with environment variable fallback
- Provider-specific defaults (OpenAI: `https://api.openai.com/v1`, Google: `https://generativelanguage.googleapis.com/v1beta`, Fal: `https://fal.run`)
- Trailing slash removal via `withoutTrailingSlash()`

**Headers Pattern:**
```typescript
const getHeaders = () =>
  withUserAgentSuffix(
    {
      Authorization: `Bearer ${apiKey}`,
      ...customHeaders,
    },
    `ai-sdk/provider/${VERSION}`,
  );
```

### 8. **Provider Options Handling**

Pattern used across all image models:

```typescript
const providerOptions = await parseProviderOptions({
  provider: 'openai',
  providerOptions,
  schema: providerImageModelOptionsSchema,
});
```

Provider options are passed through to the API request body:

```typescript
{
  model: this.modelId,
  prompt,
  n,
  ...(providerOptions.openai ?? {}),  // Spread provider-specific options
}
```

### 9. **Utility Functions**

**Location:** `/packages/provider-utils/src/`

Key utilities:

- **`convertImageModelFileToDataUri(file: ImageModelV3File): string`** - Converts file/URL to data URI
  - URL files returned as-is
  - Base64 strings wrapped in `data:{mediaType};base64,{data}`
  - Uint8Array converted to base64 then wrapped

- **`combineHeaders(...headers: Record<string, string>[]): Record<string, string>`** - Merges multiple header objects

- **`postJsonToApi()` / `postFormDataToApi()`** - Abstracts HTTP requests with response handling

- **`createJsonResponseHandler(schema)` / `createBinaryResponseHandler()`** - Response validation and parsing

### 10. **Usage in SDK Core**

**Location:** `/packages/ai/src/generate-image/generate-image.ts`

The `generateImage()` function orchestrates image generation:

```typescript
export async function generateImage({
  model,
  prompt,
  n = 1,
  maxImagesPerCall,
  size,
  aspectRatio,
  seed,
  providerOptions,
  maxRetries,
  abortSignal,
  headers,
}: {
  model: ImageModel;  // Can be string (resolved to model) or ImageModelV3/V2
  prompt: GenerateImagePrompt;
  n?: number;
  // ... other options
}): Promise<GenerateImageResult>
```

**Result Structure** (`GenerateImageResult`):
```typescript
interface GenerateImageResult {
  readonly image: GeneratedFile;                           // First image
  readonly images: Array<GeneratedFile>;                   // All images
  readonly warnings: Array<Warning>;
  readonly responses: Array<ImageModelResponseMetadata>;   // One per API call
  readonly providerMetadata: ImageModelV3ProviderMetadata; // Provider-specific data
  readonly usage: ImageModelUsage;                         // Token counts
}
```

### 11. **Implementation Variations Across Providers**

**OpenAI** (`/packages/openai/src/image/openai-image-model.ts`):
- Two endpoints: `/images/generations` (text-to-image) vs `/images/edits` (editing)
- Base64 JSON response format
- Revised prompt returned in metadata
- Token usage tracking (image_tokens, text_tokens)

**Google** (`/packages/google/src/google-generative-ai-image-model.ts`):
- Dual implementation: Imagen models vs Gemini models
- Different endpoints and response formats
- Aspect ratio vs size parameter mapping
- Dynamic maxImagesPerCall based on model type

**Black Forest Labs** (`/packages/black-forest-labs/src/black-forest-labs-image-model.ts`):
- Single image output (maxImagesPerCall = 1)
- Async polling for results (pollIntervalMillis, pollTimeoutMillis)
- Support for up to 10 input images for some models
- Aspect ratio required instead of size

**Fal** (`/packages/fal/src/fal-image-model.ts`):
- Field name mapping (camelCase to snake_case)
- Image downloading from URLs
- Support for deprecated option syntax detection
- Multiple image input handling variations

**Replicate** (`/packages/replicate/src/replicate-image-model.ts`):
- Dynamic input parameter naming (input_image, input_image_2, etc. for Flux-2)
- Prefer header for sync wait duration control
- Different endpoints for versioned vs unversioned models
- Binary image downloads

### 12. **Key Files Summary**

| Component | Location | Purpose |
|-----------|----------|---------|
| V3 Interface | `/packages/provider/src/image-model/v3/image-model-v3.ts` | Core spec |
| V3 Call Options | `/packages/provider/src/image-model/v3/image-model-v3-call-options.ts` | Input parameters |
| V3 File Type | `/packages/provider/src/image-model/v3/image-model-v3-file.ts` | File representation |
| V3 Usage | `/packages/provider/src/image-model/v3/image-model-v3-usage.ts` | Token tracking |
| OpenAI Model | `/packages/openai/src/image/openai-image-model.ts` | Complete example |
| Google Model | `/packages/google/src/google-generative-ai-image-model.ts` | Complex example |
| AI SDK generateImage | `/packages/ai/src/generate-image/generate-image.ts` | Public API |
| Provider Utils | `/packages/provider-utils/src/convert-image-model-file-to-data-uri.ts` | Helper functions |

All implementation files follow a consistent pattern while accommodating provider-specific API differences through configuration objects, options schemas, and response handlers.

