import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  FetchFunction,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartFailedResponseHandler } from './pixelart-error';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return 4;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // Parse provider options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the size parameter instead.',
      });
    }

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      body.size = size;
    }

    if (seed != null) {
      body.seed = seed;
    }

    if (pixelartOptions?.style != null) {
      body.style = pixelartOptions.style;
    }

    if (pixelartOptions?.pixelDensity != null) {
      body.pixel_density = pixelartOptions.pixelDensity;
    }

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      failedResponseHandler: pixelartFailedResponseHandler,
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The pixel art style to use for generation.
       *
       * - `pixel`: Classic pixel art style
       * - `retro`: Retro gaming aesthetic
       * - `8bit`: 8-bit console style
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * The pixel density for the generated image.
       * Higher values produce finer pixel detail.
       * Must be between 1 and 64.
       */
      pixelDensity: z.number().min(1).max(64).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

