import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { createPixelArt } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';
import { describe, it, expect, vi } from 'vitest';

vi.mock('./version', () => ({
  VERSION: '0.0.0-test',
}));

const prompt = 'A pixel art castle on a hill';

const provider = createPixelArt({ apiKey: 'test-api-key' });
const model = provider.image('pixelart-v1');

describe('doGenerate', () => {
  const testDate = new Date(2024, 0, 1);
  const server = createTestServer({
    'https://api.pixelart.ai/*': {},
  });

  function prepareResponse({
    data = [{ b64_json: 'dGVzdC1pbWFnZS1kYXRh' }],
  }: { data?: Array<{ b64_json: string }> } = {}) {
    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      body: { data },
    };
  }

  it('should pass the model and the settings', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: '256x256',
      aspectRatio: undefined,
      seed: 42,
      providerOptions: {
        pixelart: {
          style: 'pixel',
          pixelDensity: 8,
        },
      },
    });

    expect(await server.calls[0].requestBodyJson).toStrictEqual({
      model: 'pixelart-v1',
      prompt,
      n: 1,
      size: '256x256',
      seed: 42,
      style: 'pixel',
      pixel_density: 8,
    });
  });

  it('should call the correct url', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestMethod).toStrictEqual('POST');
    expect(server.calls[0].requestUrl).toStrictEqual(
      'https://api.pixelart.ai/v1/images/generations',
    );
  });

  it('should pass headers', async () => {
    prepareResponse();

    const provider = createPixelArt({
      apiKey: 'test-api-key',
      headers: {
        'Custom-Provider-Header': 'provider-header-value',
      },
    });

    await provider.image('pixelart-v1').doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
      headers: {
        'Custom-Request-Header': 'request-header-value',
      },
    });

    expect(server.calls[0].requestHeaders).toStrictEqual({
      authorization: 'Bearer test-api-key',
      'content-type': 'application/json',
      'custom-provider-header': 'provider-header-value',
      'custom-request-header': 'request-header-value',
    });

    expect(server.calls[0].requestUserAgent).toContain(
      'ai-sdk/pixelart/0.0.0-test',
    );
  });

  it('should extract the generated images', async () => {
    prepareResponse({
      data: [
        { b64_json: 'aW1hZ2UtZGF0YS0x' },
        { b64_json: 'aW1hZ2UtZGF0YS0y' },
      ],
    });

    const result = await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 2,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(result.images).toStrictEqual([
      'aW1hZ2UtZGF0YS0x',
      'aW1hZ2UtZGF0YS0y',
    ]);
  });

  it('should return response metadata', async () => {
    const modelWithTimestamp = new PixelArtImageModel('pixelart-v1', {
      provider: 'pixelart.image',
      baseURL: 'https://api.pixelart.ai/v1',
      _internal: { currentDate: () => testDate },
    });

    prepareResponse();

    const result = await modelWithTimestamp.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(result.response).toStrictEqual({
      timestamp: testDate,
      modelId: 'pixelart-v1',
      headers: expect.any(Object),
    });
  });

  it('should warn when aspectRatio is provided', async () => {
    prepareResponse();

    const result = await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: '16:9',
      seed: undefined,
      providerOptions: {},
    });

    expect(result.warnings).toStrictEqual([
      {
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the size parameter instead.',
      },
    ]);
  });

  it('should pass style provider option', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {
        pixelart: {
          style: 'retro',
        },
      },
    });

    const requestBody = await server.calls[0].requestBodyJson;
    expect(requestBody.style).toBe('retro');
  });

  it('should pass pixelDensity provider option', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {
        pixelart: {
          pixelDensity: 16,
        },
      },
    });

    const requestBody = await server.calls[0].requestBodyJson;
    expect(requestBody.pixel_density).toBe(16);
  });

  it('should pass 8bit style provider option', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {
        pixelart: {
          style: '8bit',
        },
      },
    });

    const requestBody = await server.calls[0].requestBodyJson;
    expect(requestBody.style).toBe('8bit');
  });

  it('should use custom baseURL when provided', async () => {
    const customProvider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: 'https://custom.pixelart.ai/v2',
    });

    server.urls['https://custom.pixelart.ai/*'] = {
      response: {
        type: 'json-value',
        body: { data: [{ b64_json: 'dGVzdA==' }] },
      },
    };

    await customProvider.image('pixelart-v1').doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUrl).toStrictEqual(
      'https://custom.pixelart.ai/v2/images/generations',
    );
  });

  it('should not include optional fields when not provided', async () => {
    prepareResponse();

    await model.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    const requestBody = await server.calls[0].requestBodyJson;
    expect(requestBody).toStrictEqual({
      model: 'pixelart-v1',
      prompt,
      n: 1,
    });
    expect(requestBody.size).toBeUndefined();
    expect(requestBody.seed).toBeUndefined();
    expect(requestBody.style).toBeUndefined();
    expect(requestBody.pixel_density).toBeUndefined();
  });

  it('should include response headers in metadata', async () => {
    const modelWithTimestamp = new PixelArtImageModel('pixelart-v1', {
      provider: 'pixelart.image',
      baseURL: 'https://api.pixelart.ai/v1',
      _internal: { currentDate: () => testDate },
    });

    server.urls['https://api.pixelart.ai/*'].response = {
      type: 'json-value',
      headers: {
        'custom-response-header': 'response-header-value',
      },
      body: { data: [{ b64_json: 'dGVzdA==' }] },
    };

    const result = await modelWithTimestamp.doGenerate({
      prompt,
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      aspectRatio: undefined,
      seed: undefined,
      providerOptions: {},
    });

    expect(result.response).toStrictEqual({
      timestamp: testDate,
      modelId: 'pixelart-v1',
      headers: {
        'content-length': expect.any(String),
        'content-type': 'application/json',
        'custom-response-header': 'response-header-value',
      },
    });
  });
});

