import { describe, it, expect } from 'vitest';
import { createPixelArt } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';
import { NoSuchModelError } from '@ai-sdk/provider';

describe('createPixelArt', () => {
  it('creates a provider with default settings', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.image).toBeDefined();
    expect(provider.imageModel).toBeDefined();
  });

  it('creates a provider with custom settings', () => {
    const provider = createPixelArt({
      apiKey: 'test-key',
      baseURL: 'https://custom.pixelart.ai/v1',
    });
    expect(provider.image).toBeDefined();
  });

  it('creates an image model instance', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.image('pixelart-v1');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });

  it('creates an image model instance via imageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    const model = provider.imageModel('pixelart-v2');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });

  it('throws NoSuchModelError for languageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.languageModel('test-model')).toThrow(
      NoSuchModelError,
    );
  });

  it('throws NoSuchModelError for embeddingModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.embeddingModel('test-model')).toThrow(
      NoSuchModelError,
    );
  });

  it('throws NoSuchModelError for textEmbeddingModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.textEmbeddingModel('test-model')).toThrow(
      NoSuchModelError,
    );
  });
});
